script:
frappe.ui.form.on('ContratoVenta', {

    before_save: function(frm) {
        if (frm.doc.__islocal) {
            let proyecto = (frm.doc.proyecto || '').toUpperCase().replace(/[^A-Z0-9]/g, '-').replace(/-+/g, '-').replace(/^-|-$/g, '');
            let lote = (frm.doc.numero_lote || '').toUpperCase().replace(/[^A-Z0-9]/g, '-').replace(/-+/g, '-').replace(/^-|-$/g, '');
            let prefix = 'CONT-' + proyecto + '-' + lote + '-';
            return frappe.call({
                method: 'frappe.client.get_count',
                args: { doctype: 'ContratoVenta', filters: [['name', 'like', prefix + '%']] },
                async: false,
                callback: function(r) {
                    let consecutivo = String((r.message || 0) + 1).padStart(3, '0');
                    frm.doc.name = prefix + consecutivo;
                }
            });
        }
    },

    refresh: function(frm) {
        frm.set_df_property('lote',                    'read_only', 1);
        frm.set_df_property('proyecto',                'read_only', 1);
        frm.set_df_property('area_terreno_m2',         'read_only', 1);
        frm.set_df_property('area_terreno_vrs2',       'read_only', 1);
        frm.set_df_property('modelo',                  'read_only', 1);
        frm.set_df_property('m2_construccion',         'read_only', 1);
        frm.set_df_property('precio_total',            'read_only', 1);
        frm.set_df_property('monto_prima',             'read_only', 1);
        frm.set_df_property('monto_reserva',           'read_only', 1);
        frm.set_df_property('saldo_prima',             'read_only', 1);
        frm.set_df_property('monto_financiar',         'read_only', 1);
        frm.set_df_property('fecha_estimada_entrega',  'read_only', 1);
        frm.set_df_property('tabla_de_ambientes',      'read_only', 1);
        frm.set_df_property('descripcion_construccion','read_only', 1);

        frm.set_query('carta_reserva', function() {
            return {
                filters: [
                    ['estado', '=', 'Activa'],
                    ['tiene_contrato', '=', 0]
                ]
            };
        });

        if (!frm.doc.__islocal) {
            frm.set_df_property('carta_reserva', 'read_only', 1);
        }
    },

    validate: function(frm) {
        if (!frm.doc.fecha) frappe.throw('Debe ingresar la Fecha.');
        if (!frm.doc.carta_reserva) frappe.throw('Debe seleccionar la Carta de Reserva.');
        if (!frm.doc.lote) frappe.throw('Debe seleccionar el Lote.');
        if (!frm.doc.plazo_entrega) frappe.throw('Debe ingresar el Plazo de Entrega en meses.');
        if (frm.doc.desembolsos && frm.doc.desembolsos.length > 0) {
            let total = 0;
            frm.doc.desembolsos.forEach(function(d) { total += (d.porcentaje || 0); });
            if (parseFloat(total.toFixed(2)) !== 100) {
                frappe.throw('Los porcentajes de desembolso suman ' + total.toFixed(2) + '%. Deben sumar exactamente 100%.');
            }
        }
    },

    lote: function(frm) {
        if (frm.doc.lote) {
            frappe.db.get_doc('Lotes', frm.doc.lote).then(function(doc) {
                frm.set_value('proyecto', doc.proyecto);
                frm.set_value('area_terreno_m2', doc.m2_terreno);
                frm.set_value('area_terreno_vrs2', doc.v2_terreno);
                if (doc.catalogo_modelos) {
                    frappe.db.get_doc('CatalogoModelos', doc.catalogo_modelos).then(function(catalogo) {
                        frm.set_value('modelo', catalogo.modelo);
                        frm.set_value('m2_construccion', catalogo.area_construccion);
                    });
                }
            });
        }
    },

    carta_reserva: function(frm) {
        if (frm.doc.carta_reserva) {
            frappe.db.get_doc('CartaReserva', frm.doc.carta_reserva).then(function(doc) {
                if (doc.estado === 'Cancelada') {
                    frappe.msgprint({ title: 'Carta Cancelada', message: 'La Carta <b>' + frm.doc.carta_reserva + '</b> está cancelada.', indicator: 'red' });
                    frm.set_value('carta_reserva', '');
                    return;
                }
                frm.set_df_property('lote', 'read_only', 0);
                frm.set_value('lote',                    doc.lote);
                frm.set_value('nombre_comprador',        doc.nombre_solicitante);
                frm.set_value('profesion_comprador',     doc.profesion);
                frm.set_value('estado_comprador',        doc.estado_civil);
                frm.set_value('cedula_comprador',        doc.numero_identificacion);
                frm.set_value('domicilio_comprador',     doc.direccion);
                frm.set_value('nombre_comprador2',       doc.nombre_conyuge);
                frm.set_value('profesion_comprador2',    doc.profesion_conyuge);
                frm.set_value('estado_civil_comprador2', doc.estado_civil_conyuge);
                frm.set_value('cedula_comprador2',       doc.numero_identificacion_conyuge);
                frm.set_value('domicilio_comprador2',    doc.direccion_conyuge);
                frm.set_value('precio_total',            doc.precio_total);
                frm.set_value('monto_prima',             doc.monto_prima);
                frm.set_value('monto_reserva',           doc.monto_reservacion);
                frm.set_value('saldo_prima',             doc.saldo_neto_prima);
                frm.set_value('monto_financiar',         doc.monto_financiar);
                frm.set_df_property('lote', 'read_only', 1);

                // Snapshot de ambientes y descripción del lote
                frappe.call({
                    method: 'frappe.client.get',
                    args: { doctype: 'Lotes', name: doc.lote },
                    callback: function(r) {
                        if (r.message) {
                            frm.set_df_property('tabla_de_ambientes', 'read_only', 0);
                            frm.clear_table('tabla_de_ambientes');
                            (r.message.ambientes || []).forEach(function(a) {
                                let row = frm.add_child('tabla_de_ambientes');
                                row.ambiente = a.ambiente;
                                row.cantidad = a.cantidad;
                            });
                            frm.refresh_field('tabla_de_ambientes');
                            frm.set_df_property('tabla_de_ambientes', 'read_only', 1);

                            frm.set_df_property('descripcion_construccion', 'read_only', 0);
                            frm.set_value('descripcion_construccion', r.message.descripcion_construccion);
                            frm.set_df_property('descripcion_construccion', 'read_only', 1);
                        }
                    }
                });

                frm.clear_table('desembolsos');
                ['Primer Desembolso', 'Segundo Desembolso', 'Tercer Desembolso', 'Cuarto Desembolso'].forEach(function(concepto, i) {
                    let row = frm.add_child('desembolsos');
                    row.numero     = String(i + 1);
                    row.concepto   = concepto;
                    row.porcentaje = 25;
                    row.monto      = parseFloat(((doc.monto_financiar || 0) * 0.25).toFixed(2));
                    row.estado     = 'Pendiente';
                    row.realizado  = 0;
                });
                frm.refresh_field('desembolsos');
            });
        }
    },

    plazo_entrega: function(frm) { calcularFecha(frm); },
    fecha:         function(frm) { calcularFecha(frm); }

});

function calcularFecha(frm) {
    if (frm.doc.fecha && frm.doc.plazo_entrega) {
        frm.set_value('fecha_estimada_entrega', frappe.datetime.add_months(frm.doc.fecha, frm.doc.plazo_entrega));
    }
}

frappe.ui.form.on('CatalogoModelos', {
    area_construccion: function(frm) {
        calcularVarasCatalogo(frm);
    },
    onload: function(frm) {
        calcularVarasCatalogo(frm);
    },
    refresh: function(frm) {
        calcularVarasCatalogo(frm);
    }
});

function calcularVarasCatalogo(frm) {
    if (frm.doc.area_construccion && frm.doc.area_construccion > 0) {
        frm.set_value('area_varas', parseFloat((frm.doc.area_construccion * 1.4196).toFixed(3)));
    } else {
        frm.set_value('area_varas', 0);
    }
}

frappe.ui.form.on('Lotes', {
    refresh: function(frm) {
        if (frm.doc.estado === 'Disponible') {
            frm.set_indicator('Disponible', 'green');
        } else if (frm.doc.estado === 'Reservado') {
            frm.set_indicator('Reservado', 'orange');
        } else if (frm.doc.estado === 'Vendido') {
            frm.set_indicator('Vendido', 'red');
        }
    },
    m2_terreno: function(frm) {
        frm.set_value('v2_terreno', (frm.doc.m2_terreno || 0) * 1.4196);
    },
    m2_casa: function(frm) {
        frm.set_value('v2_casa', (frm.doc.m2_casa || 0) * 1.4196);
    },
    catalogo_modelos: function(frm) {
        if (frm.doc.catalogo_modelos) {
            frappe.db.get_doc('CatalogoModelos', frm.doc.catalogo_modelos)
            .then(function(catalogo) {
                frm.set_value('m2_casa', catalogo.area_construccion);
                frm.set_value('v2_casa', (catalogo.area_construccion || 0) * 1.4196);
                frm.set_value('descripcion_construccion', catalogo.descripcion);
                frm.clear_table('ambientes');
                (catalogo.ambientes || []).forEach(function(a) {
                    let row = frm.add_child('ambientes');
                    row.ambiente = a.ambiente;
                    row.m2 = a.m2;
                });
                frm.refresh_field('ambientes');
            });
        }
    }
});

frappe.ui.form.on('CartaReserva', {
    onload: function(frm) {
        if (!frm.doc.__islocal) frm._lote_guardado = frm.doc.lote;
        frm.set_query('lote', function() {
            var filtros = [['estado','=','Disponible']];
            if (frm.doc.proyecto) filtros.push(['proyecto','=',frm.doc.proyecto]);
            return { filters: filtros };
        });
        if (frm.doc.__islocal && !frm.doc.vendedor) {
            frm.set_value('vendedor', frappe.session.user);
        }
    },
    before_save: function(frm) {
        calcularCarta(frm);
        if (!frm.doc.__islocal) return;
        var p = (frm.doc.proyecto||'').toUpperCase().replace(/[^A-Z0-9]/g,'-').replace(/-+/g,'-').replace(/^-|-$/g,'');
        var l = (frm.doc.numero_lote||'').toUpperCase().replace(/[^A-Z0-9]/g,'-').replace(/-+/g,'-').replace(/^-|-$/g,'');
        var prefix = 'RES-'+p+'-'+l+'-';
        return frappe.call({
            method: 'frappe.client.get_count',
            args: { doctype: 'CartaReserva', filters: [['name','like',prefix+'%']] },
            async: false,
            callback: function(r) { frm.doc.name = prefix + String((r.message||0)+1).padStart(3,'0'); }
        });
    },
    refresh: function(frm) {
        if (!frm.doc.__islocal) frm._lote_guardado = frm.doc.lote;
        if (frm.doc.__islocal) {
            frm.set_df_property('lote', 'read_only', 0);
            if (!frm.doc.vendedor) {
                frm.set_value('vendedor', frappe.session.user);
            }
        }
        frm.set_df_property('precio',           'read_only', 1);
        frm.set_df_property('precio_total',     'read_only', 1);
        frm.set_df_property('monto_prima',      'read_only', 1);
        frm.set_df_property('saldo_neto_prima', 'read_only', 1);
        frm.set_df_property('monto_financiar',  'read_only', 1);
        frm.set_query('lote', function() {
            var filtros = [['estado','=','Disponible']];
            if (frm.doc.proyecto) filtros.push(['proyecto','=',frm.doc.proyecto]);
            return { filters: filtros };
        });
        if (frm.doc.estado === 'Activa') frm.set_indicator('Activa', 'blue');
        if (frm.doc.estado === 'Cancelada') frm.set_indicator('Cancelada', 'red');
        if (frm.doc.lote) {
            frappe.db.get_doc('Lotes', frm.doc.lote).then(function(d) {
                frm._m2_extras = d.m2_extras;
                frm._v2_extras = d.v2_extras;
                calcularCarta(frm);
            });
        }
    },
    validate: function(frm) { calcularCarta(frm); },
    after_save: function(frm) {
        if (frm._lote_anterior && frm._lote_anterior !== frm.doc.lote) {
            frappe.db.set_value('Lotes', frm._lote_anterior, 'estado', 'Disponible').then(function() {
                frappe.show_alert({ message: 'Lote '+frm._lote_anterior+' liberado', indicator: 'orange' });
            });
        }
        if (frm.doc.lote && frm.doc.estado !== 'Cancelada') {
            frappe.db.set_value('Lotes', frm.doc.lote, 'estado', 'Reservado').then(function() {
                frappe.show_alert({ message: 'Lote '+frm.doc.lote+' reservado', indicator: 'green' });
            });
        }
        frm._lote_guardado = frm.doc.lote;
        frm._lote_anterior = null;
        setTimeout(function() { frappe.set_route('Form', 'CartaReserva', frm.doc.name); }, 300);
    },
    proyecto: function(frm) {
        frm.set_query('lote', function() {
            var filtros = [['estado','=','Disponible']];
            if (frm.doc.proyecto) filtros.push(['proyecto','=',frm.doc.proyecto]);
            return { filters: filtros };
        });
        frm.set_value('lote', '');
    },
    estado: function(frm) {
        if (frm.doc.estado !== 'Cancelada' || !frm.doc.lote) return;
        frappe.confirm('¿Cancelar reserva? El lote '+frm.doc.lote+' volverá a Disponible.',
            function() {
                frappe.db.set_value('Lotes', frm.doc.lote, 'estado', 'Disponible').then(function() {
                    frappe.show_alert({ message: 'Lote '+frm.doc.lote+' disponible', indicator: 'blue' });
                    frm.save();
                });
            },
            function() { frm.set_value('estado', 'Activa'); }
        );
    }
});

frappe.ui.form.on('Adendum', {

    before_save: function(frm) {
        if (frm.doc.__islocal) {
            let proyecto = (frm.doc.proyecto || '').toUpperCase().replace(/[^A-Z0-9]/g, '-').replace(/-+/g, '-').replace(/^-|-$/g, '');
            let lote = (frm.doc.lote || '').toUpperCase().replace(/[^A-Z0-9]/g, '-').replace(/-+/g, '-').replace(/^-|-$/g, '');
            let prefix = 'ADEN-' + proyecto + '-' + lote + '-';
            return frappe.call({
                method: 'frappe.client.get_count',
                args: {
                    doctype: 'Adendum',
                    filters: [['name', 'like', prefix + '%']]
                },
                async: false,
                callback: function(r) {
                    let consecutivo = String((r.message || 0) + 1).padStart(3, '0');
                    frm.doc.name = prefix + consecutivo;
                }
            });
        }
    },

    refresh: function(frm) {
        frm.set_df_property('lote',      'read_only', 1);
        frm.set_df_property('proyecto',  'read_only', 1);
        frm.set_df_property('modelo',    'read_only', 1);
        frm.set_df_property('comprador', 'read_only', 1);

        aplicar_visibilidad(frm);
        if (frm.doc.tipo === 'Proforma') {
            agregar_base_lote(frm);
        }
    },

    tipo_adendum: function(frm) {
        aplicar_visibilidad(frm);
        if (frm.doc.tipo === 'Proforma') {
            agregar_base_lote(frm);
        }
    },

    contrato: function(frm) {
        if (frm.doc.contrato) {
            frappe.db.get_doc('ContratoVenta', frm.doc.contrato)
            .then(function(d) {
                frm.set_value('lote',      d.lote);
                frm.set_value('proyecto',  d.proyecto);
                frm.set_value('modelo',    d.modelo);
                frm.set_value('comprador', d.nombre_comprador);
                if (frm.doc.tipo === 'Proforma') {
                    agregar_base_lote(frm);
                }
            });
        }
    },

    validate: function(frm) {
        if (!frm.doc.contrato) {
            frappe.throw('⚠️ El campo <b>Contrato</b> es obligatorio.'); return;
        }
        if (!frm.doc.fecha) {
            frappe.throw('⚠️ El campo <b>Fecha</b> es obligatorio.'); return;
        }
        if (!frm.doc.tipo) {
            frappe.throw('⚠️ El campo <b>Tipo de Adéndum</b> es obligatorio.'); return;
        }

        if (!frm.doc.extras || frm.doc.extras.length === 0) {
            frappe.throw('⚠️ Debe agregar al menos un item en la tabla de extras.'); return;
        }
        for (let i = 0; i < frm.doc.extras.length; i++) {
            let row = frm.doc.extras[i];
            if (!row.descripcion) {
                frappe.throw('⚠️ Fila ' + (i + 1) + ': el campo <b>Descripción</b> es obligatorio.'); return;
            }
            if (!row.monto || row.monto <= 0) {
                frappe.throw('⚠️ Fila ' + (i + 1) + ': el <b>Monto</b> debe ser mayor a cero.'); return;
            }
        }

        if (!frm.doc.total || frm.doc.total <= 0) {
            frappe.throw('⚠️ El <b>Total</b> debe ser mayor a cero.'); return;
        }

        if (frm.doc.tipo !== 'Proforma') {
            if (!frm.doc.forma_pago) {
                frappe.throw('⚠️ El campo <b>Forma de Pago</b> es obligatorio para este tipo.'); return;
            }
        } else {
            if (!frm.doc.asesor) {
                frappe.throw('⚠️ El campo <b>Asesor</b> es obligatorio para Proforma.'); return;
            }
            if (!frm.doc.revisado_por) {
                frappe.throw('⚠️ El campo <b>Revisado por</b> es obligatorio para Proforma.'); return;
            }
        }

        if (frm.doc.tipo === 'Adéndum' && frm.doc.contrato && frm.doc.__islocal) {
            frappe.call({
                method: 'frappe.client.get_count',
                args: {
                    doctype: 'Adendum',
                    filters: { contrato: frm.doc.contrato, tipo: 'Adéndum' }
                },
                async: false,
                callback: function(r) {
                    if (r.message > 0) {
                        frappe.throw('Ya existe un Adéndum para el contrato ' + frm.doc.contrato + '. Solo se permite uno por contrato.');
                    }
                }
            });
        }
    }

});

frappe.ui.form.on('Adendum', {
    extras_before_remove: function(frm, cdt, cdn) {
        let row = locals[cdt][cdn];
        if (row.seccion === 'Base') {
            frappe.throw('⚠️ La fila base del lote no puede eliminarse.');
        }
    }
});

frappe.ui.form.on('AdendumExtra', {
    monto:          function(frm) { calcular_total(frm); },
    seccion:        function(frm) { calcular_total(frm); },
    extras_remove:  function(frm) { calcular_total(frm); },
    cantidad:       function(frm) { calcular_total(frm); }
});

// ── Funciones auxiliares ──────────────────────────────────────────────────────

function aplicar_visibilidad(frm) {
    let tipo = frm.doc.tipo || 'Adéndum';
    let es_proforma = tipo === 'Proforma';

    frm.toggle_display('asesor',             es_proforma);
    frm.toggle_display('revisado_por',       es_proforma);
    frm.toggle_display('valido_por',         es_proforma);
    frm.toggle_display('descuento_especial', es_proforma);
    frm.toggle_display('forma_pago',         !es_proforma);

    let label_tabla = es_proforma ? "Items (use Sección para agrupar)" : "Extras";
    frm.set_df_property('extras', 'label', label_tabla);

    frm.refresh_fields();
}

function calcular_total(frm) {
    let total = 0;
    (frm.doc.extras || []).forEach(function(row) {
        if (row.seccion === 'Crédito') {
            total -= (row.monto || 0) * (row.cantidad || 1);
        } else {
            total += (row.monto || 0) * (row.cantidad || 1);
        }
    });
    if (frm.doc.tipo === 'Proforma') {
        total -= (frm.doc.descuento_especial || 0);
    }
    frm.set_value('total', parseFloat(total.toFixed(2)));
}

function agregar_base_lote(frm) {
    if (frm.doc.tipo !== 'Proforma' || !frm.doc.contrato) return;

    // Si ya existe una fila Base, solo bloquearla
    let tiene_base = (frm.doc.extras || []).some(function(r) { return r.seccion === 'Base'; });
    if (tiene_base) {
        bloquear_filas_base(frm);
        return;
    }

    frappe.db.get_value('ContratoVenta', frm.doc.contrato, 'carta_reserva')
    .then(function(r) {
        let carta = (r && r.message) ? r.message.carta_reserva : null;
        if (!carta) return;
        return frappe.db.get_value('CartaReserva', carta, 'precio_total');
    })
    .then(function(r) {
        if (!r) return;
        let precio = (r && r.message) ? (r.message.precio_total || 0) : 0;
        let row = frm.add_child('extras', {
            seccion:     'Base',
            descripcion: 'Lote',
            cantidad:    1,
            monto:       precio
        });
        frm.refresh_field('extras');
        calcular_total(frm);
        bloquear_filas_base(frm);
    });
}

function bloquear_filas_base(frm) {
    setTimeout(function() {
        var grid = frm.fields_dict['extras'] && frm.fields_dict['extras'].grid;
        if (!grid) return;
        grid.grid_rows.forEach(function(grid_row) {
            if (grid_row.doc && grid_row.doc.seccion === 'Base') {
                // Bloquear apertura del formulario de edición
                grid_row.open_form = function() {
                    frappe.show_alert({ message: 'El precio base del lote no es editable.', indicator: 'orange' });
                };
                // Ocultar botón de edición y selección
                grid_row.row.find('.btn-open-row').hide();
                grid_row.row.find('.grid-row-check').css('pointer-events', 'none');
                // Estilo visual de solo lectura
                grid_row.row.find('td').css({
                    'background-color': '#f5f5f5',
                    'color': '#555'
                });
            }
        });
    }, 300);
}

frappe.ui.form.on('urbDesembolso', {
    porcentaje: function(frm, cdt, cdn) {
