frappe.ui.form.on('CatalogoModelos', {
    validate: function(frm) {
        if (!frm.doc.precio_base) {
            frappe.throw('El campo Precio Base es obligatorio.');
        }
        if (!frm.doc.monto_reserva) {
            frappe.throw('El campo Monto de Reserva es obligatorio.');
        }
        if (!frm.doc.area_construccion) {
            frappe.throw('El campo Área de Construcción es obligatorio.');
        }
        if (frm.doc.__islocal) {
            frappe.call({
                method: 'frappe.client.get_count',
                args: {
                    doctype: 'CatalogoModelos',
                    filters: [['name', '=', frm.doc.name]]
                },
                async: false,
                callback: function(r) {
                    if (r.message > 0) {
                        frappe.throw(`Ya existe un modelo con el nombre <b>${frm.doc.name}</b>.`);
                    }
                }
            });
        }
        if (frm.doc.precio_base <= 0) {
            frappe.throw('El Precio Base debe ser mayor a cero.');
        }
        if (frm.doc.monto_reserva > frm.doc.precio_base) {
            frappe.throw('El Monto de Reserva no puede ser mayor al Precio Base.');
        }
    }
});

frappe.ui.form.on('Lotes', {
    before_save: function(frm) {
        // --- Campos obligatorios ---
        const requeridos = [
            { campo: 'proyecto', etiqueta: 'Proyecto' },
            { campo: 'bloque', etiqueta: 'Bloque' },
            { campo: 'numero_lote', etiqueta: 'Número de Lote' },
            { campo: 'm2_terreno', etiqueta: 'M² Terreno' }
        ];
        for (let r of requeridos) {
            if (!frm.doc[r.campo]) {
                frappe.throw(`⚠️ El campo <b>${r.etiqueta}</b> es obligatorio.`);
            }
        }
        // --- M2 mayor a cero ---
        if (frm.doc.m2_terreno <= 0) {
            frappe.throw('⚠️ Los <b>M² de Terreno</b> deben ser mayores a cero.');
        }
        // --- No duplicar número de lote por proyecto ---
        if (!frm.doc.__islocal && frm.doc.proyecto && frm.doc.numero_lote) {
            return;
        }
        frappe.call({
            method: 'frappe.client.get_list',
            args: {
                doctype: 'Lotes',
                filters: [
                    ['proyecto', '=', frm.doc.proyecto],
                    ['numero_lote', '=', frm.doc.numero_lote],
                    ['name', '!=', frm.doc.name]
                ],
                fields: ['name'],
                limit: 1
            },
            callback: function(r) {
                if (r.message && r.message.length > 0) {
                    frappe.throw(
                        `⚠️ Ya existe el lote <b>${frm.doc.numero_lote}</b> en el proyecto <b>${frm.doc.proyecto}</b>. Registro: ${r.message[0].name}`
                    );
                }
            }
        });
    }
});

