frappe.ui.form.on('ContratoVenta', {
    validate: function(frm) {
        const requeridos = [
            { f: 'carta_reserva',       label: 'Carta de Reserva' },
            { f: 'fecha',               label: 'Fecha' },
            { f: 'lote',                label: 'Lote' },
            { f: 'plazo_entrega',       label: 'Plazo de Entrega' },
            { f: 'nombre_comprador',    label: 'Nombre Comprador' },
            { f: 'cedula_comprador',    label: 'Cédula Comprador' },
        ];
        for (let r of requeridos) {
            if (!frm.doc[r.f]) {
                frappe.throw(`⚠️ El campo <b>${r.label}</b> es obligatorio.`); return;
            }
        }
        if (!frm.doc.precio_total || frm.doc.precio_total <= 0) {
            frappe.throw('⚠️ El <b>Precio Total</b> debe ser mayor a cero.'); return;
        }
        if (frm.doc.desembolsos && frm.doc.desembolsos.length > 0) {
            let total = frm.doc.desembolsos.reduce(function(sum, row) {
                return sum + (parseFloat(row.porcentaje) || 0);
            }, 0);
            total = Math.round(total * 100) / 100;
            if (total !== 100) {
                frappe.throw(
                    `⚠️ Los <b>Desembolsos</b> deben sumar <b>100%</b>. ` +
                    `Actualmente suman <b>${total}%</b>.`
                ); return;
            }
        } else {
            frappe.throw('⚠️ Debe tener al menos un <b>Desembolso</b> registrado.'); return;
        }
    }
});

