function calcularVarasCatalogo(frm) {
    if (frm.doc.area_construccion && frm.doc.area_construccion > 0) {
        let varas = parseFloat((frm.doc.area_construccion * 1.4196).toFixed(3));
        frm.set_value('area_varas', varas);
    } else {
        frm.set_value('area_varas', 0);
    }
}

frappe.ui.form.on('CartaReserva', {
    lote: function(frm) {
        frm._lote_anterior = frm._lote_guardado || null;
        frm.set_df_property('lote', 'read_only', 0);
        if (!frm.doc.lote) return;
        frappe.db.get_doc('Lotes', frm.doc.lote).then(function(d) {
            frm.set_value('proyecto', d.proyecto);
            frm.set_value('bloque', d.bloque);
            frm.set_value('numero_lote', d.numero_lote);
            frm.set_value('catalogo_modelos', d.catalogo_modelos);
            frm.set_value('m2_terreno', d.m2_terreno);
            frm.set_value('v2_terreno', d.v2_terreno);
            frm.set_value('esquinero', d.esquinero || 'No');
            frm._m2_extras = d.m2_extras;
            frm._v2_extras = d.v2_extras;
            if (d.catalogo_modelos) {
                frappe.db.get_doc('CatalogoModelos', d.catalogo_modelos).then(function(c) {
                    frm.set_value('precio', c.precio_base);
                    frm.set_value('monto_reservacion', c.monto_reserva);
                    calcularCarta(frm);
                });
            } else {
                calcularCarta(frm);
            }
        });
    },
    precio:            function(frm) { asegurarExtrasCarta(frm); },
    costo_adicional:   function(frm) { asegurarExtrasCarta(frm); },
    prima_porcentaje:  function(frm) { asegurarExtrasCarta(frm); },
    monto_reservacion: function(frm) { asegurarExtrasCarta(frm); },
    descuento:         function(frm) { asegurarExtrasCarta(frm); },
    esquinero:         function(frm) { asegurarExtrasCarta(frm); }
});

function asegurarExtrasCarta(frm) {
    if (frm.doc.lote) {
        frappe.db.get_doc('Lotes', frm.doc.lote).then(function(d) {
            frm._m2_extras = d.m2_extras;
            frm._v2_extras = d.v2_extras;
            calcularCarta(frm);
        });
    } else {
        calcularCarta(frm);
    }
}

function calcularCarta(frm) {
    var s = (frm.doc.precio||0) + (frm.doc.costo_adicional||0);
    if (frm.doc.esquinero === 'Si') s += 2000;
    var cv = (frm._v2_extras||0) * 80;
    s += cv;
    var md = frm.doc.descuento || 0;
    var pt = s - md;
    var mp = frm.doc.prima_porcentaje || 0;
    var sn = mp - (frm.doc.monto_reservacion||0);
    frm.set_value('precio_total', pt);
    frm.set_value('monto_prima', mp);
    frm.set_value('saldo_neto_prima', sn < 0 ? 0 : sn);
    frm.set_value('monto_financiar', pt - mp);
    var obs = [];
    if (frm.doc.esquinero === 'Si') obs.push('Lote esquinero: cargo adicional de $2,000.00');
    if (cv > 0) obs.push('Varas extras: '+(frm._v2_extras||0)+' V2 x $80.00 = $'+cv.toLocaleString());
    if ((frm._m2_extras||0) > 0) obs.push('Metros extras: '+frm._m2_extras+' M2 / '+(frm._v2_extras||0)+' V2');
    if (md > 0) obs.push('Descuento: $' + md.toLocaleString());
    frm.set_value('observaciones', obs.join('\n'));
}

