frappe.ui.form.on("SeguimientoObra", {

  onload: function(frm) {
    aplicar_visibilidad_contrato(frm);
    if (frm.doc.__islocal && !frm.doc.fecha_inicio) {
      frm.set_value("fecha_inicio", frappe.datetime.get_today());
    }
  },

  refresh: function(frm) {
    aplicar_visibilidad_contrato(frm);
    frm.set_df_property("porcentaje_avance", "read_only", 1);

    if (!frm.doc.actividades || frm.doc.actividades.length === 0) {
      frm.add_custom_button(__("Cargar Actividades Estándar"), function() {
        cargar_actividades_estandar(frm);
      });
    }
    setTimeout(function() {
      mostrar_barra_progreso(frm, frm.doc.porcentaje_avance || 0);
    }, 100);
  },

  lote: function(frm) {
    if (frm.doc.lote) {
      frappe.db.get_value("Lotes", frm.doc.lote, "proyecto", function(value) {
        if (value && value.proyecto) {
          frm.set_value("proyecto", value.proyecto);
        }
      });
    } else {
      frm.set_value("proyecto", null);
    }
  },

  tipo_seguimiento: function(frm) {
    aplicar_visibilidad_contrato(frm);
    if (frm.doc.tipo_seguimiento === "Inventario") {
      frm.set_value("contrato", null);
      frm.set_value("lote", null);
      frm.set_value("proyecto", null);
      frm.set_value("fecha_entrega_estimada", null);
    }
  },

  contrato: function(frm) {
    if (frm.doc.contrato && frm.doc.tipo_seguimiento === "Contrato") {
      frappe.call({
        method: "frappe.client.get_value",
        args: {
          doctype: "ContratoVenta",
          filters: { name: frm.doc.contrato },
          fieldname: ["lote", "fecha_estimada_entrega"]
        },
        callback: function(r) {
          if (r.message) {
            if (r.message.lote) {
              frm.set_value("lote", r.message.lote);
              frm.refresh_field("lote");
            }
            if (r.message.fecha_estimada_entrega) {
              frm.set_value("fecha_entrega_estimada", r.message.fecha_estimada_entrega);
            }
          }
        }
      });
    } else {
      frm.set_value("lote", null);
      frm.set_value("proyecto", null);
      frm.set_value("fecha_entrega_estimada", null);
    }
  }

});

// ── Funciones auxiliares ──────────────────────────────────────

function aplicar_visibilidad_contrato(frm) {
  let es_contrato = frm.doc.tipo_seguimiento === "Contrato";
  frm.toggle_display("contrato", es_contrato);
  frm.set_df_property("contrato", "reqd", es_contrato ? 1 : 0);
}

function get_color(pct) {
  return pct < 30 ? "#f39c12" : pct < 70 ? "#3498db" : pct < 100 ? "#27ae60" : "#2ecc71";
}

function mostrar_barra_progreso(frm, pct) {
  pct = flt(pct) || 0;
  let $existente = $(frm.wrapper).find(".gicosa-barra-avance");
  if ($existente.length) { actualizar_barra_existente(frm, pct); return; }
  let color = get_color(pct);
  let html = '<div class="gicosa-barra-avance" style="margin:4px 0;">'
    + '<div style="display:flex;justify-content:space-between;margin-bottom:4px;">'
    + '<span style="font-weight:600;color:#333;">Avance de Obra</span>'
    + '<span class="gicosa-barra-pct" style="font-weight:700;color:' + color + ';">' + pct.toFixed(1) + '%</span>'
    + '</div>'
    + '<div style="background:#e0e0e0;border-radius:8px;height:14px;overflow:hidden;">'
    + '<div class="gicosa-barra-fill" style="width:' + pct + '%;background:' + color + ';height:100%;border-radius:8px;transition:width 0.4s ease;"></div>'
    + '</div></div>';
  frm.dashboard.set_headline(html);
}

function actualizar_barra_existente(frm, pct) {
  pct = flt(pct) || 0;
  let $b = $(frm.wrapper).find(".gicosa-barra-avance");
  if (!$b.length) return;
  let color = get_color(pct);
  $b.find(".gicosa-barra-fill").css({ width: pct + "%", background: color });
  $b.find(".gicosa-barra-pct").text(pct.toFixed(1) + "%").css("color", color);
}

function calcular_avance(frm) {
  let total = 0;
  (frm.doc.actividades || []).forEach(function(row) {
    if (row.estado === "Completada") total += flt(row.peso);
  });
  total = Math.min(total, 100);
  if (flt(frm.doc.porcentaje_avance) !== total) {
    frm.set_value("porcentaje_avance", total);
  }
  actualizar_barra_existente(frm, total);
  actualizar_estado_obra(frm, total);
}

function actualizar_estado_obra(frm, porcentaje) {
  if (frm.doc.estado_obra === "Entregada") return;
  let nuevo;
  if (porcentaje === 0) nuevo = "Pendiente";
  else if (porcentaje < 100) nuevo = "En Proceso";
  else nuevo = "Terminada";
  if (nuevo && frm.doc.estado_obra !== nuevo) {
    frm.doc.estado_obra = nuevo;
    frm.refresh_field("estado_obra");
  }
}

function validar_suma_pesos(frm) {
  let suma = 0;
  (frm.doc.actividades || []).forEach(function(row) { suma += flt(row.peso); });
  if (suma > 100) {
    frappe.msgprint({
      title: __("Advertencia de Pesos"), indicator: "orange",
      message: __("La suma de los pesos es <b>" + suma + "%</b>. Debe ser 100%.")
    });
  }
}

function cargar_actividades_estandar(frm) {
  let lista = [
    { actividad: "Cimentacion y fundaciones",      peso: 10 },
    { actividad: "Estructura y paredes",           peso: 20 },
    { actividad: "Cubierta y techo",               peso: 15 },
    { actividad: "Instalaciones electricas",       peso: 10 },
    { actividad: "Instalaciones hidro-sanitarias", peso: 10 },
    { actividad: "Piso y ceramica",                peso: 10 },
    { actividad: "Puertas y ventanas",             peso: 10 },
    { actividad: "Acabados y pintura",             peso: 10 },
    { actividad: "Pre-entrega y detalles",         peso:  5 },
    { actividad: "Entrega final",                  peso:  0 }
  ];
  lista.forEach(function(a) {
    let row = frm.add_child("actividades");
    row.actividad   = a.actividad;
    row.peso        = a.peso;
    row.estado      = "Pendiente";
    row.responsable = frappe.session.user;
  });
  frm.refresh_field("actividades");
  frm.remove_custom_button("Cargar Actividades Estándar");
  frappe.show_alert({ message: __("Actividades estandar cargadas."), indicator: "green" });
}

