frappe.ui.form.on("ActividadObra", {
  actividades_add: function(frm, cdt, cdn) {
    frappe.model.set_value(cdt, cdn, "responsable", frappe.session.user);
  },
  estado: function(frm, cdt, cdn) {
    let row = locals[cdt][cdn];
    if (row.estado === "En Proceso") {
      if (!row.fecha_inicio) {
        frappe.model.set_value(cdt, cdn, "estado", "Pendiente");
        frappe.msgprint({
          title: __("Fecha requerida"),
          indicator: "orange",
          message: __("Debe ingresar la <b>Fecha de Inicio</b> antes de marcar la actividad como En Proceso.")
        });
        return;
      }
    }
    if (row.estado === "Completada") {
      if (!row.fecha_inicio || !row.fecha_fin) {
        frappe.model.set_value(cdt, cdn, "estado", "Pendiente");
        frappe.msgprint({
          title: __("Fechas requeridas"),
          indicator: "orange",
          message: __("Debe ingresar la <b>Fecha de Inicio</b> y la <b>Fecha de Fin</b> antes de marcar la actividad como Completada.")
        });
        return;
      }
    }
    calcular_avance(frm);
  },
  peso: function(frm, cdt, cdn) {
    validar_suma_pesos(frm);
    calcular_avance(frm);
  },
  actividades_remove: function(frm) {
    calcular_avance(frm);
  }
});

