            });
        }, 'Crear');

        // Botón Nuevo Reconocimiento de Deuda — verifica si ya existe cualquier tipo
        frm.add_custom_button('Nuevo Reconocimiento de Deuda', function() {
            frappe.call({
                method: 'frappe.client.get_count',
                args: {
                    doctype: 'Adendum',
                    filters: { contrato: frm.doc.name }
                },
                callback: function(r) {
                    if (r.message > 0) {
                        frappe.msgprint({
                            title: 'Adéndum existente',
                            message: 'Ya existe un documento vinculado a este contrato. Solo se permite uno por contrato.',
                            indicator: 'red'
                        });
                    } else {
                        frappe.new_doc('Adendum', {
                            contrato:  frm.doc.name,
                            lote:      frm.doc.lote,
                            proyecto:  frm.doc.proyecto,
                            modelo:    frm.doc.modelo,
                            comprador: frm.doc.nombre_comprador,
                            tipo:      'Reconocimiento de Deuda'
                        });
                    }
                }
            });
        }, 'Crear');

        // Tabla de adéndums con tipo incluido
        frappe.call({
            method: 'frappe.client.get_list',
            args: {
                doctype: 'Adendum',
                filters: { contrato: frm.doc.name },
                fields: ['name', 'fecha', 'total', 'tipo', 'forma_pago'],
                order_by: 'fecha asc'
            },
            callback: function(r) {
                let html = '';
                if (r.message && r.message.length > 0) {
                    html += '<table class="table table-bordered table-sm" style="font-size:13px;">'
                          + '<thead style="background:#f5f5f5;"><tr>'
                          + '<th>N°</th><th>Tipo</th><th>Fecha</th><th>Total</th><th>Forma de Pago</th><th></th>'
                          + '</tr></thead><tbody>';
                    r.message.forEach(function(a) {
                        let link = frappe.utils.get_form_link('Adendum', a.name);
                        html += '<tr>'
                              + '<td><a href="' + link + '">' + a.name + '</a></td>'
                              + '<td>' + (a.tipo || '') + '</td>'
                              + '<td>' + (frappe.datetime.str_to_user(a.fecha) || '') + '</td>'
                              + '<td>U$ ' + parseFloat(a.total || 0).toFixed(2) + '</td>'
                              + '<td>' + (a.forma_pago || '') + '</td>'
                              + '<td><a class="btn btn-xs btn-default" href="' + link + '">Ver</a></td>'
                              + '</tr>';
                    });
                    html += '</tbody></table>';
                } else {
                    html = '<p class="text-muted" style="font-size:13px">No hay adéndums registrados.</p>';
                }
                frm.fields_dict.adendums_html.$wrapper.html(html);
            }
        });
    }
});

