// Client Script: ContratoVenta-Ambientes
// Botón para actualizar ambientes y descripción desde el lote
// ============================================================
frappe.ui.form.on('ContratoVenta', {
    refresh: function(frm) {
        if (!frm.doc.__islocal && frm.doc.lote) {
            frm.add_custom_button(__("Actualizar Ambientes desde Lote"), function() {
                frappe.confirm(
                    "¿Actualizar los ambientes y descripción desde el lote actual? Esto sobreescribirá los datos actuales del contrato.",
                    function() {
                        frappe.call({
                            method: 'frappe.client.get',
                            args: { doctype: 'Lotes', name: frm.doc.lote },
                            callback: function(r) {
                                if (r.message) {
                                    frm.set_df_property('tabla_de_ambientes', 'read_only', 0);
                                    frm.clear_table('tabla_de_ambientes');
                                    (r.message.ambientes || []).forEach(function(a) {
                                        let row = frm.add_child('tabla_de_ambientes');
                                        row.ambiente = a.ambiente;
                                        row.cantidad = a.cantidad;
                                    });
                                    frm.refresh_field('tabla_de_ambientes');
                                    frm.set_df_property('tabla_de_ambientes', 'read_only', 1);
                                    frm.set_df_property('descripcion_construccion', 'read_only', 0);
                                    frm.set_value('descripcion_construccion', r.message.descripcion_construccion);
                                    frm.set_df_property('descripcion_construccion', 'read_only', 1);
                                    frappe.show_alert({
                                        message: __("Ambientes y descripción actualizados correctamente."),
                                        indicator: "green"
                                    });
                                }
                            }
                        });
                    }
                );
            });
        }
    }
});
